1	//! Shared band-table renderer for tick-valued histograms.
2	//!
3	//! Both `TProbe` (fast path, direct-histogram) and `TProbe2`
4	//! (scope API, records → drain) store hardware tick deltas and
5	//! want the same band-table output shape — min/p1/…/p99/max
6	//! rows with first/last/range/count/mean columns, plus summary
7	//! lines for mean, stdev, mean min-p99, stdev min-p99. This
8	//! module provides a single implementation both can call into.
9	//!
10	//! Display unit is chosen by `as_ticks`: `false` converts stored
11	//! tick values to nanoseconds via [`crate::ticks::ticks_per_ns`];
12	//! `true` shows raw ticks.
13	
14	use hdrhistogram::Histogram;
15	
16	use crate::harness::{fmt_commas, fmt_commas_f64};
17	use crate::ticks;
18	
19	const BOUNDARY_PCTS: &[f64] = &[
20	    0.0, 0.01, 0.10, 0.20, 0.30, 0.40, 0.50, 0.60, 0.70, 0.80, 0.90, 0.99, 1.0,
21	];
22	const BOUNDARY_NAMES: &[&str] = &[
23	    "min", "p1", "p10", "p20", "p30", "p40", "p50", "p60", "p70", "p80", "p90", "p99", "max",
24	];
25	
26	/// Render a band-table report for `hist`, interpreting stored
27	/// values as hardware ticks. `kind` is the header label
28	/// (`"tprobe"`, `"tprobe2"`, …) and `name` is the probe's name.
29	/// `as_ticks=false` converts to ns; `true` keeps raw ticks.
30	pub(crate) fn render(kind: &str, name: &str, hist: &Histogram<u64>, as_ticks: bool) {
31	    let sample_count = hist.len();
32	    println!("  {kind}: {name} [count={}]", fmt_commas(sample_count));
33	    if sample_count == 0 {
34	        println!();
35	        return;
36	    }
37	
38	    let unit = if as_ticks { "tk" } else { "ns" };
39	    let tpn = ticks::ticks_per_ns();
40	    let conv = |v: u64| -> f64 { if as_ticks { v as f64 } else { v as f64 / tpn } };
41	    let conv_f = |v: f64| -> f64 { if as_ticks { v } else { v / tpn } };
42	
43	    let n_bands = BOUNDARY_PCTS.len() - 1;
44	    let mut band_first = vec![u64::MAX; n_bands];
45	    let mut band_last = vec![0u64; n_bands];
46	    let mut band_count = vec![0u64; n_bands];
47	    let mut band_sum = vec![0u128; n_bands];
48	
49	    let mut cumulative = 0u64;
50	    for iv in hist.iter_recorded() {
51	        let value = iv.value_iterated_to();
52	        let count = iv.count_at_value();
53	        let mid_rank = (cumulative as f64 + count as f64 / 2.0) / sample_count as f64;
54	        let idx = BOUNDARY_PCTS[1..]
55	            .iter()
56	            .position(|&b| mid_rank < b)
57	            .unwrap_or(n_bands - 1);
58	        band_first[idx] = band_first[idx].min(value);
59	        band_last[idx] = band_last[idx].max(value);
60	        band_count[idx] += count;
61	        band_sum[idx] += value as u128 * count as u128;
62	        cumulative += count;
63	    }
64	
65	    struct BandRow {
66	        label: String,
67	        first: String,
68	        last: String,
69	        range: String,
70	        count: String,
71	        mean: String,
72	    }
73	
74	    let mut rows: Vec<BandRow> = Vec::new();
75	    for i in 0..n_bands {
76	        if band_count[i] == 0 {
77	            continue;
78	        }
79	        let mean_val = band_sum[i] as f64 / band_count[i] as f64;
80	        let range_raw = band_last[i] - band_first[i] + 1;
81	        rows.push(BandRow {
82	            label: format!("{}-{}", BOUNDARY_NAMES[i], BOUNDARY_NAMES[i + 1]),
83	            first: fmt_commas_f64(conv(band_first[i]), 0),
84	            last: fmt_commas_f64(conv(band_last[i]), 0),
85	            range: fmt_commas_f64(conv(range_raw), 0),
86	            count: fmt_commas(band_count[i]),
87	            mean: fmt_commas_f64(conv_f(mean_val), 0),
88	        });
89	    }
90	
91	    let label_w = rows
92	        .iter()
93	        .map(|r| r.label.len())
94	        .max()
95	        .unwrap_or(0)
96	        .max("stdev min-p99".len());
97	    let first_w = rows.iter().map(|r| r.first.len()).max().unwrap_or(0);
98	    let last_w = rows.iter().map(|r| r.last.len()).max().unwrap_or(0);
99	    let range_w = rows.iter().map(|r| r.range.len()).max().unwrap_or(0);
100	    let count_w = rows.iter().map(|r| r.count.len()).max().unwrap_or(0);
101	    let mean_w = rows.iter().map(|r| r.mean.len()).max().unwrap_or(0);
102	
103	    const INDENT: &str = "    ";
104	    const GAP: &str = "    ";
105	
106	    let first_col = INDENT.len() + label_w + 1 + first_w;
107	    let unit_len = 1 + unit.len();
108	    let last_gap = unit_len + GAP.len() + last_w;
109	    let range_gap = unit_len + GAP.len() + range_w;
110	    let count_gap = unit_len + GAP.len() + count_w;
111	    let mean_gap = GAP.len() + mean_w;
112	    println!(
113	        "{:>first_col$}{:>last_gap$}{:>range_gap$}{:>count_gap$}{:>mean_gap$}",
114	        "first", "last", "range", "count", "mean",
115	    );
116	
117	    for r in &rows {
118	        println!(
119	            "{INDENT}{:<label_w$} {:>first_w$} {unit}{GAP}{:>last_w$} {unit}{GAP}{:>range_w$} {unit}{GAP}{:>count_w$}{GAP}{:>mean_w$} {unit}",
120	            r.label, r.first, r.last, r.range, r.count, r.mean,
121	        );
122	    }
123	
124	    let hist_mean = hist.mean();
125	    let skip = first_w
126	        + unit_len
127	        + GAP.len()
128	        + last_w
129	        + unit_len
130	        + GAP.len()
131	        + range_w
132	        + unit_len
133	        + GAP.len()
134	        + count_w;
135	    println!(
136	        "{INDENT}{:<label_w$} {:>skip$}{GAP}{:>mean_w$} {unit}",
137	        "mean",
138	        "",
139	        fmt_commas_f64(conv_f(hist_mean), 0),
140	    );
141	    println!(
142	        "{INDENT}{:<label_w$} {:>skip$}{GAP}{:>mean_w$} {unit}",
143	        "stdev",
144	        "",
145	        fmt_commas_f64(conv_f(hist.stdev()), 0),
146	    );
147	
148	    let trim_count: u64 = band_count[..n_bands - 1].iter().sum();
149	    if trim_count > 0 {
150	        let trim_sum: u128 = band_sum[..n_bands - 1].iter().sum();
151	        let trim_mean = trim_sum as f64 / trim_count as f64;
152	
153	        let mut trim_var_sum = 0.0f64;
154	        let mut trim_var_count = 0u64;
155	        let mut cum = 0u64;
156	        for iv in hist.iter_recorded() {
157	            let value = iv.value_iterated_to();
158	            let count = iv.count_at_value();
159	            let mid_rank = (cum as f64 + count as f64 / 2.0) / sample_count as f64;
